#!/usr/bin/env bash
# PulseTeach AI 团队一键安装 — 自包含版本
# 用法: bash install-all.sh
# 无需服务器，直接运行即可

set -euo pipefail

RESET="\033[0m"; BOLD="\033[1m"; GREEN="\033[32m"; YELLOW="\033[33m"; DIM="\033[2m"
ok()   { printf "  ${GREEN}✓${RESET} %s\n" "$*"; }
log()  { printf "  ${DIM}·${RESET} %s\n" "$*"; }
warn() { printf "  ${YELLOW}⚠${RESET}  %s\n" "$*"; }

PE_PLATFORM="http://YOUR_PLATFORM_HOST"

printf "\n  ${BOLD}PulseTeach AI 团队环境安装${RESET}\n\n"


# ── Node.js ───────────────────────────────────────────────────────────────────
install_node() {
  if command -v brew &>/dev/null; then
    log "通过 Homebrew 安装 Node.js ..."
    brew install node -q
  else
    log "下载 Node.js 安装包 (80MB，请稍候)..."
    TMP_PKG="/tmp/node-lts-install.pkg"
    curl -fsSL "https://nodejs.org/dist/v22.14.0/node-v22.14.0.pkg" -o "$TMP_PKG"
    log "安装中（需要管理员密码）..."
    sudo installer -pkg "$TMP_PKG" -target / 2>/dev/null
    rm -f "$TMP_PKG"
    export PATH="/usr/local/bin:/usr/bin:$PATH"
    # 修复 sudo 安装后的 npm 权限问题
    log "修复 npm 目录权限 ..."
    sudo chown -R "$(whoami)" ~/.npm 2>/dev/null || true
    sudo chown -R "$(whoami)" /usr/local/lib/node_modules /usr/local/bin 2>/dev/null || true
  fi
}

if command -v node &>/dev/null; then
  NODE_MAJOR="$(node --version | sed 's/v//' | cut -d. -f1)"
  if [[ "$NODE_MAJOR" -ge 18 ]]; then ok "Node.js $(node --version)"
  else warn "Node.js 版本太低，重新安装 ..."; install_node; fi
else
  log "未检测到 Node.js，安装中 ..."; install_node
fi
ok "npm $(npm --version)"

# ── Codex CLI ─────────────────────────────────────────────────────────────────
log "安装 Codex CLI ..."
npm install -g @openai/codex --silent --unsafe-perm=true 2>/dev/null || sudo npm install -g @openai/codex --silent --unsafe-perm=true
ok "Codex CLI $(codex --version 2>/dev/null || echo 'installed')"

# ── OpenClaw ──────────────────────────────────────────────────────────────────
log "安装 OpenClaw ..."
npm install -g openclaw --silent --unsafe-perm=true 2>/dev/null || sudo npm install -g openclaw --silent --unsafe-perm=true
ok "OpenClaw $(openclaw --version 2>/dev/null || echo 'installed')"

# OpenClaw 基础配置（API Key 由 pt login 登录后自动同步）
mkdir -p "$HOME/.openclaw" "$HOME/.openclaw/workspace"
if [[ ! -f "$HOME/.openclaw/openclaw.json" ]]; then
  cat > "$HOME/.openclaw/openclaw.json" << JSON
{
  "models": { "mode": "merge", "providers": {} },
  "agents": {
    "defaults": {
      "workspace": "${HOME}/.openclaw/workspace",
      "compaction": { "mode": "safeguard" }
    }
  },
  "gateway": {
    "port": 18789,
    "mode": "local",
    "bind": "loopback",
    "auth": { "mode": "token" }
  }
}
JSON
  ok "OpenClaw 配置写入完成"
else
  ok "OpenClaw 已有配置，跳过"
fi

# ── Gateway ───────────────────────────────────────────────────────────────────
log "启动 OpenClaw Gateway ..."
timeout 30 openclaw gateway install 2>/dev/null || true
timeout 15 openclaw gateway start  2>/dev/null || true
for i in 1 2 3 4 5; do
  sleep 1
  if timeout 5 openclaw gateway status 2>/dev/null | grep -q "running"; then
    ok "Gateway 已启动"; break
  fi
  [[ $i -eq 5 ]] && ok "Gateway 后台运行中"
done

# ── PulseTeach AI CLI（内嵌版）─────────────────────────────────────────────────────
log "安装 PulseTeach AI CLI ..."
PT_BIN=""
install_pe() {
  local target="$1"
  python3 -c "" "$target" && chmod +x "$target"
}

if install_pe /usr/local/bin/pe 2>/dev/null; then
  ln -sf /usr/local/bin/pe /usr/local/bin/pt 2>/dev/null || cp /usr/local/bin/pe /usr/local/bin/pt 2>/dev/null || true
  PT_BIN="/usr/local/bin/pt"
else
  mkdir -p "$HOME/.local/bin"
  install_pe "$HOME/.local/bin/pe"
  ln -sf "$HOME/.local/bin/pe" "$HOME/.local/bin/pt" 2>/dev/null || cp "$HOME/.local/bin/pe" "$HOME/.local/bin/pt" 2>/dev/null || true
  PT_BIN="$HOME/.local/bin/pt"
  for rc in ~/.zshrc ~/.bashrc ~/.bash_profile; do
    [[ -f "$rc" ]] && grep -q '\.local/bin' "$rc" && continue
    [[ -f "$rc" ]] && echo 'export PATH="$HOME/.local/bin:$PATH"' >> "$rc"
  done
  export PATH="$HOME/.local/bin:$PATH"
fi
python3 -m pip install requests -q 2>/dev/null || true
ok "pt CLI 已安装 ($PT_BIN)"

# ── PulseTeach AI 登录 ────────────────────────────────────────────────────────────
printf "\n  ${BOLD}登录 PulseTeach AI 平台${RESET}\n"

if pt whoami &>/dev/null; then
  ok "已登录 PulseTeach AI（$(pt whoami 2>/dev/null | grep 用户名 | awk '{print $2}')）"
  pe sync-config 2>/dev/null || true
else
  printf "  账号格式：姓名全拼，密码：全拼+123\n\n"
  pt login --url "$PE_PLATFORM"
fi

# 登录后重启 Gateway，使 team provider 配置生效
log "重启 OpenClaw Gateway（同步 AI 配置）..."
timeout 10 openclaw gateway restart 2>/dev/null || true
sleep 2

# ── 安装 PulseTeach AI Skill ───────────────────────────────────────────────────────
SKILL_DIR="$HOME/.openclaw/skills/pt-space"
mkdir -p "$SKILL_DIR"
cat > "$SKILL_DIR/SKILL.md" << 'SKILL_EOF'
---
name: pt-space
description: "Deploy Streamlit apps to PulseTeach AI platform via pt CLI. Use when: user wants to build or deploy an app, use pt deploy/list/logs/stop, or manage PulseTeach AI applications."
metadata: { "openclaw": { "emoji": "🚀", "requires": { "bins": ["pe"] } } }
---
# PulseTeach AI Skill — 需求到上线全流程

你是一个 AI 工程助手，能够帮助用户将需求转化为可运行的 Streamlit 应用并部署到 PulseTeach AI 平台。

---

## 什么时候使用这个 Skill

用户说类似以下内容时启动：
- "帮我做一个 xxx 工具"
- "部署 xxx 应用"
- "我需要一个 xxx 功能"
- "上线一个 xxx"
- "pt deploy" / "发布应用"

---

## 完整工作流程

### 第一步：理解需求

和用户确认：
1. **应用名称**（用于目录名和平台标识，英文小写，如 `text-cleaner`）
2. **功能描述**（做什么，输入什么，输出什么）
3. **需要哪些 Python 库**（如有特殊需求）

### 第二步：获取代码规范

在生成代码前，先获取平台的代码规范 Prompt：

```bash
pt rules
```

这会输出平台管理员设定的代码规范，**必须严格遵守**，包括：
- Streamlit 应用结构要求
- 历史记录保存方式（run_id/username/timestamp/inputs/summary/output_files 格式）
- 路径规范（DATA_DIR 自适应写法）
- 禁止事项（calamine、Windows 专用包、硬编码路径等）
- 其他团队约定

### 第三步：生成代码（用 Codex）

在以下目录创建项目（如果不存在则新建）：
```
~/Desktop/pe-apps/{应用名}/
```

在该目录启动 Codex，告知：
1. 代码规范（来自 pt rules 的输出）
2. 用户需求
3. 需要生成：`app.py` + `requirements.txt`（复杂工具还需 `config.py` + `src/`）

**app.py 核心要求：**
- `st.set_page_config(...)` 必须是第一行
- DATA_DIR 使用自适应写法：`Path("/app/data") if Path("/app").exists() else BASE_DIR / "data"`
- 有运行结果时写入 HISTORY_DIR，格式包含 run_id/username/timestamp/inputs/summary/output_files
- 所有异常用 try-except + st.error() 处理，不暴露 Traceback

**requirements.txt 要求：**
- 每行一个包名，版本用 >=
- 不包含标准库
- 禁止使用 calamine（Excel 用 openpyxl）

### 第四步：部署到 PulseTeach AI

代码写好后，在项目目录执行：

```bash
cd ~/Desktop/pe-apps/{应用名}
pt deploy --name "{应用名称}" --slug {slug} --desc "{一句话描述}"
```

> **注意**：小龙虾已知应用名称和 slug（在第一步和用户确认过），直接传入参数，无需交互输入。

`pt deploy` 会自动：
1. 将目录打包为 zip（忽略 .git、__pycache__ 等）
2. 上传到平台
3. 构建 Docker 镜像
4. 启动容器并配置路由
5. 返回访问链接

**首次部署**：通过 `--name`、`--slug`、`--desc` 直接传入参数，跳过交互提示。
**后续更新**：再次运行 `pt deploy` 即可，会自动识别已有应用（无需重复传参）。

### 第五步：告知用户结果

部署成功后，告知用户：
- 应用访问链接（如 `http://YOUR_PLATFORM_HOST/apps/text-cleaner/`）
- 需要登录 PulseTeach AI 账号才能访问

---

## 常用 pt 命令速查

```bash
# 账号
pt login              # 登录平台
pt whoami             # 查看当前登录状态
pt status             # 快速检查平台连通性和 token 有效性

# 应用管理
pt list               # 查看所有应用（running 状态显示 URL）
pt deploy --name "{名称}" --slug {slug} --desc "{描述}"  # 首次部署（带参数，无需交互）
pt deploy             # 更新已有应用（再次部署）
pt info {slug}        # 查看应用详情
pt logs {slug}        # 查看构建/运行日志
pt stop {slug}        # 停止应用
pt restart {slug}     # 重启应用
pt delete {slug}      # 删除应用（需确认）
pe open {slug}        # 在浏览器打开应用

# 应用历史
pt history            # 查看所有应用的最近运行记录（全局）
pt history {slug}     # 查看指定应用的运行历史

# 文件
pt files list         # 列出所有应用的历史输出文件
pt files list {slug}  # 列出指定应用的历史输出文件
pt files download {slug} {filepath}  # 下载文件到当前目录

# 规范
pt rules              # 查看代码规范 Prompt（生成代码前必须先看）
pt rules edit         # 在编辑器中修改规范（管理员）
pt rules update --file {file}  # 从文件更新规范（管理员）

# 统计（管理员）
pt stats              # 查看使用统计

# 用户管理（管理员）
pt users list
pt users create --username {u} --password {p} --role user
pt users batch --project {name} --count {n} --password {pw}
pt users reset-pw {id|username} {新密码}
pt users toggle {id|username}   # 启用/禁用
pt users delete {id|username}   # 删除用户（需确认）

# Prompt 模板
pt prompts list
pt prompts get {id}   # 查看完整内容
pt prompts update {id} --title {t} --content {c}
```

---

## 故障排除

**部署失败 / 构建错误：**
```bash
pt logs {slug}
```
常见原因：requirements.txt 包名不存在、app.py 语法错误、依赖冲突

**应用无法访问（401）：**
- `pt whoami` 检查登录状态
- `pt info {slug}` 查看应用状态
- `pt restart {slug}` 重启应用

**pt 命令找不到：**
```bash
export PATH="$HOME/.local/bin:$PATH"
```

---

## 注意事项

1. 代码中**不要**硬编码敏感信息（API key 放 config.py，config.py 不提交 git）
2. 应用目录放在 `~/Desktop/pe-apps/` 下
3. Slug 一旦设定不可更改（需删除重建）
4. 生成代码前**必须**先运行 `pt rules` 获取最新规范

SKILL_EOF
ok "PulseTeach AI Skill 已安装"

# ── 重启 Gateway 并打开 OpenClaw ─────────────────────────────────────────────
printf "\n  ${BOLD}安装完成！${RESET}\n"
log "重启 OpenClaw Gateway ..."
openclaw gateway stop 2>/dev/null || true
sleep 1

OPENCLAW_BIN="$(which openclaw)"
osascript << APPLESCRIPT
tell application "Terminal"
  activate
  do script "${OPENCLAW_BIN} gateway"
  delay 2
  do script "${OPENCLAW_BIN} tui --message '请学习 pt-space skill，熟悉所有 pt 命令和完整部署流程，之后我说需求你就能直接帮我开发并部署到 PulseTeach AI 平台。'"
end tell
APPLESCRIPT

openclaw dashboard 2>/dev/null || true
open "http://YOUR_PLATFORM_HOST"
printf "  PulseTeach AI: http://YOUR_PLATFORM_HOST\n\n"
